);

-- Final storage_pool_type (LOCAL, NFS, OVERLAYBD only)
CREATE TYPE storage_pool_type AS ENUM (
    'LOCAL',
    'NFS',
    'OVERLAYBD'
);

CREATE TYPE storage_pool_status AS ENUM (
    'ACTIVE',
