-- hosts
CREATE TABLE IF NOT EXISTS hosts (
    id                       UUID DEFAULT gen_random_uuid() PRIMARY KEY NOT NULL,
    name                     VARCHAR(50) UNIQUE NOT NULL,
    address                  VARCHAR(16) UNIQUE NOT NULL,
    port                     INT4 NOT NULL,
    status                   host_status NOT NULL,
    host_user                VARCHAR(32) NOT NULL,
    password                 BYTEA NOT NULL,
    cloud_hypervisor_version TEXT,
    kernel_version           TEXT,
    total_cpus               INT,
    total_memory_bytes       BIGINT,
    available_memory_bytes   BIGINT,
    load_average             DOUBLE PRECISION,
    disk_total_bytes         BIGINT,
    disk_available_bytes     BIGINT,
    resources_updated_at     TIMESTAMPTZ,
    node_version             TEXT,
    last_deployed_image      TEXT,
    architecture             VARCHAR(16)
);

-- networks
CREATE TABLE IF NOT EXISTS networks (
    id         UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    name       VARCHAR(50) UNIQUE NOT NULL,
    subnet     CIDR NOT NULL,
    type       VARCHAR(50),
    gateway    INET,
    dns        INET,
    status     network_status NOT NULL DEFAULT 'ACTIVE',
    created_at TIMESTAMP WITHOUT TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITHOUT TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

