-- network_interfaces (nullable network_id, mac_address, ip_address)
CREATE TABLE IF NOT EXISTS network_interfaces (
    id           UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    vm_id        UUID NOT NULL REFERENCES vms(id) ON DELETE CASCADE,
    network_id   UUID REFERENCES networks(id) ON DELETE CASCADE,
    mac_address  MACADDR,
    ip_address   INET,
    interface_type interface_type NOT NULL,
    device_id    VARCHAR(50) NOT NULL,
    tap_name     VARCHAR(50),
    host_mac     MACADDR,
    mtu          INTEGER DEFAULT 1500,
    vhost_user   BOOLEAN DEFAULT false,
    vhost_socket VARCHAR(255),
    vhost_mode   VARCHAR(20),
    num_queues   INTEGER DEFAULT 1,
    queue_size   INTEGER DEFAULT 256,
    rate_limiter JSONB,
    offload_tso  BOOLEAN DEFAULT true,
    offload_ufo  BOOLEAN DEFAULT true,
    offload_csum BOOLEAN DEFAULT true,
    pci_segment  INTEGER DEFAULT 0,
    iommu        BOOLEAN DEFAULT false,
    created_at   TIMESTAMP WITHOUT TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    updated_at   TIMESTAMP WITHOUT TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT network_interfaces_vm_device_unique UNIQUE (vm_id, device_id),
    CONSTRAINT check_mtu_positive         CHECK (mtu > 0),
    CONSTRAINT check_num_queues_positive  CHECK (num_queues > 0),
    CONSTRAINT check_queue_size_positive  CHECK (queue_size > 0),
    CONSTRAINT check_vhost_socket         CHECK (
        (vhost_user = false) OR (vhost_user = true AND vhost_socket IS NOT NULL)
    )
);

