-- vm_disks (device_name → device_path → kept; disk_id → logical_name)
CREATE TABLE IF NOT EXISTS vm_disks (
    id                    UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    vm_id                 UUID NOT NULL REFERENCES vms(id) ON DELETE CASCADE,
    storage_object_id     UUID REFERENCES storage_objects(id),
    device_path           VARCHAR(20) NOT NULL,
    boot_order            INTEGER,
    read_only             BOOLEAN DEFAULT false,
    config                JSONB NOT NULL DEFAULT '{}'::jsonb,
    logical_name          VARCHAR(50) NOT NULL,
    direct                BOOLEAN DEFAULT false,
    vhost_user            BOOLEAN DEFAULT false,
    vhost_socket          VARCHAR(255),
    num_queues            INTEGER DEFAULT 1,
    queue_size            INTEGER DEFAULT 128,
    rate_limiter          JSONB,
    rate_limit_group      VARCHAR(100),
    pci_segment           INTEGER DEFAULT 0,
    serial_number         VARCHAR(100),
    upper_storage_object_id UUID REFERENCES storage_objects(id) ON DELETE SET NULL,
    created_at            TIMESTAMP WITHOUT TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT vm_disks_vm_logical_name_unique UNIQUE (vm_id, logical_name),
    CONSTRAINT check_disk_path_or_vhost CHECK (
        (vhost_user = true AND vhost_socket IS NOT NULL) OR
        (vhost_user = false AND storage_object_id IS NOT NULL)
    ),
    CONSTRAINT check_num_queues_positive CHECK (num_queues > 0),
    CONSTRAINT check_queue_size_positive CHECK (queue_size > 0)
);

CREATE INDEX IF NOT EXISTS idx_vm_disks_vm           ON vm_disks(vm_id);
CREATE INDEX IF NOT EXISTS idx_vm_disks_storage      ON vm_disks(storage_object_id);
CREATE INDEX IF NOT EXISTS idx_vm_disks_boot         ON vm_disks(boot_order) WHERE boot_order IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_vm_disks_logical_name ON vm_disks(logical_name);
CREATE INDEX IF NOT EXISTS idx_vm_disks_vhost        ON vm_disks(vhost_user) WHERE vhost_user = true;
CREATE INDEX IF NOT EXISTS idx_vm_disks_rate_limit_group ON vm_disks(rate_limit_group) WHERE rate_limit_group IS NOT NULL;

