);

CREATE INDEX IF NOT EXISTS vm_snapshots_vm_id_idx       ON vm_snapshots(vm_id);
CREATE INDEX IF NOT EXISTS vm_snapshots_storage_obj_idx ON vm_snapshots(storage_object_id);

