    vm_id            UUID NOT NULL UNIQUE REFERENCES vms(id) ON DELETE CASCADE,
    vm_template_id   UUID REFERENCES vm_templates(id) ON DELETE SET NULL,
    name             TEXT NOT NULL UNIQUE,
    status           sandbox_status NOT NULL DEFAULT 'PROVISIONING',
    idle_timeout_secs INT NOT NULL DEFAULT 300,
    last_activity_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    error_message    TEXT,
    created_at       TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_sandboxes_status        ON sandboxes (status);
CREATE INDEX IF NOT EXISTS idx_sandboxes_last_activity ON sandboxes (last_activity_at) WHERE status = 'READY';

-- host_numa_nodes
CREATE TABLE IF NOT EXISTS host_numa_nodes (
    id           UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    host_id      UUID NOT NULL REFERENCES hosts(id) ON DELETE CASCADE,
    node_id      INTEGER NOT NULL,
    cpu_list     TEXT NOT NULL DEFAULT '',
    memory_bytes BIGINT,
    distances    INTEGER[] NOT NULL DEFAULT '{}',
    updated_at   TIMESTAMPTZ DEFAULT NOW(),
    UNIQUE (host_id, node_id)
);

CREATE INDEX IF NOT EXISTS idx_host_numa_nodes_host ON host_numa_nodes (host_id);
